const isHol = ds => Object.prototype.hasOwnProperty.call(holidays, ds);
const isWknd = date => [0, 6].includes(date.getDay());
const isOff = (date, ds) => isWknd(date) || isHol(ds);

function deriveAttendanceStatus(rowData = {}, date = null, ds = '') {
  if (date && isOff(date, ds)) return 'Libur';
  const raw = String(rowData.status ?? rowData.ket ?? '').trim().toLowerCase();
  if (!raw) return 'Hadir';
  if (/(ijin|izin)/.test(raw)) return 'Ijin';
  if (/sakit/.test(raw)) return 'Sakit';
  if (/cuti/.test(raw)) return 'Cuti';
  if (/(tidak masuk|alpha|alpa|absen)/.test(raw)) return 'Tidak Masuk';
  return 'Hadir';
}

function getRandomTime(startH, startM, endH, endM) {
  const startTotalMinutes = startH * 60 + startM;
  const endTotalMinutes = endH * 60 + endM;
  const randomMinutes = Math.floor(Math.random() * (endTotalMinutes - startTotalMinutes + 1)) + startTotalMinutes;
  const h = Math.floor(randomMinutes / 60);
  const m = randomMinutes % 60;
  return `${String(h).padStart(2, '0')}.${String(m).padStart(2, '0')}`;
}

function normalizeAttendanceRow(rowData = {}, date = null, ds = '') {
  const status = deriveAttendanceStatus(rowData, date, ds);
  const isPresent = status === 'Hadir';

  if (isPresent && !attData[ds]) attData[ds] = { status: 'Hadir' };
  if (isPresent && !attData[ds].masuk) attData[ds].masuk = getRandomTime(7, 0, 8, 5);
  if (isPresent && !attData[ds].pulang) attData[ds].pulang = getRandomTime(16, 5, 19, 20);

  return {
    status,
    isPresent,
    masuk: isPresent ? attData[ds].masuk : '',
    pulang: isPresent ? attData[ds].pulang : ''
  };
}

function getAttendanceStatusCode(status, off = false) {
  if (off || status === 'Libur') return 'libur';
  switch (status) {
    case 'Ijin': return 'ijin';
    case 'Sakit': return 'sakit';
    case 'Cuti': return 'cuti';
    case 'Tidak Masuk': return 'alpha';
    default: return 'hadir';
  }
}

function getAttendanceColorMeta(code) {
  const map = {
    hadir: { fill: '#ffffff', wordFill: 'FFFFFF', text: '#000000' },
    libur: { fill: '#fca5a5', wordFill: 'F4CCCC', text: '#7f1d1d' },
    ijin: { fill: '#fef3c7', wordFill: 'FFF2CC', text: '#92400e' },
    sakit: { fill: '#dbeafe', wordFill: 'D9EAF7', text: '#1d4ed8' },
    cuti: { fill: '#e5e7eb', wordFill: 'E7E6E6', text: '#374151' },
    alpha: { fill: '#fed7aa', wordFill: 'FCE5CD', text: '#9a3412' }
  };
  return map[code] || map.hadir;
}

function renderAttendanceStatusOptions(selected) {
  return ATTENDANCE_STATUS_OPTIONS.map(status => `<option value="${status}" ${status === selected ? 'selected' : ''}>${status}</option>`).join('');
}

function applyAttendanceRowUi(row, status) {
  if (!row) return;
  const code = getAttendanceStatusCode(status, false);
  const color = getAttendanceColorMeta(code);
  const isPresent = status === 'Hadir';
  row.querySelectorAll('td').forEach(td => {
    td.style.background = isPresent ? '' : color.fill;
    td.style.color = isPresent ? '' : color.text;
    td.style.fontWeight = isPresent ? '' : '600';
  });
  row.querySelectorAll('input[data-f="masuk"], input[data-f="pulang"]').forEach(input => {
    input.disabled = !isPresent;
    input.classList.toggle('is-disabled', !isPresent);
  });
}

function updateAttStatus(el) {
  const ds = el.dataset.d;
  if (!attData[ds]) attData[ds] = {};
  attData[ds].status = el.value;
  const row = el.closest('tr');
  const masukEl = row ? row.querySelector('input[data-f="masuk"]') : null;
  const pulangEl = row ? row.querySelector('input[data-f="pulang"]') : null;

  if (el.value === 'Hadir') {
    attData[ds].masuk = attData[ds].masuk || getRandomTime(7, 0, 8, 5);
    attData[ds].pulang = attData[ds].pulang || getRandomTime(16, 5, 19, 20);
    attData[ds].ket = '';
    if (masukEl) masukEl.value = attData[ds].masuk;
    if (pulangEl) pulangEl.value = attData[ds].pulang;
  } else {
    attData[ds].masuk = '';
    attData[ds].pulang = '';
    attData[ds].ket = el.value;
    if (masukEl) masukEl.value = '';
    if (pulangEl) pulangEl.value = '';
  }

  applyAttendanceRowUi(row, el.value);
}

function randomizeAllAttendance() {
  if (!curM || !curY) return;
  for (let d = 1; d <= daysInMonth(curM, curY); d++) {
    const ds = iso(new Date(curY, curM - 1, d));
    if (attData[ds]) {
      const status = deriveAttendanceStatus(attData[ds], new Date(curY, curM - 1, d), ds);
      if (status === 'Hadir') {
        attData[ds].masuk = getRandomTime(7, 0, 8, 5);
        attData[ds].pulang = getRandomTime(16, 5, 19, 20);
      }
    }
  }
  buildHad(curM, curY);
  toast('Waktu kehadiran berhasil diacak ulang.', 'success');
}

function getXmlText(node, ns) {
  return Array.from(node.getElementsByTagNameNS(ns, 't')).map(item => item.textContent).join(' ');
}

function applyWordRowFill(row, ns, fill) {
  const doc = row.ownerDocument;
  const cells = Array.from(row.getElementsByTagNameNS(ns, 'tc'));
  cells.forEach(cell => {
    let tcPr = cell.getElementsByTagNameNS(ns, 'tcPr')[0];
    if (!tcPr) {
      tcPr = doc.createElementNS(ns, 'w:tcPr');
      cell.insertBefore(tcPr, cell.firstChild);
    }
    let shd = tcPr.getElementsByTagNameNS(ns, 'shd')[0];
    if (!shd) {
      shd = doc.createElementNS(ns, 'w:shd');
      tcPr.appendChild(shd);
    }
    shd.setAttribute('w:val', 'clear');
    shd.setAttribute('w:fill', fill);
  });
}

function colorAttendanceTableInWord(zip, kehadiran) {
  try {
    const xml = zip.file('word/document.xml').asText();
    const parser = new DOMParser();
    const xmlDoc = parser.parseFromString(xml, 'application/xml');
    const ns = 'http://schemas.openxmlformats.org/wordprocessingml/2006/main';
    const tables = Array.from(xmlDoc.getElementsByTagNameNS(ns, 'tbl'));
    const targetTable = tables.find(tbl => {
      const tableText = getXmlText(tbl, ns);
      return tableText.includes('Laporan Kehadiran') && tableText.includes('Ijin/Sakit/Cuti');
    });
    if (!targetTable) return;

    const rows = Array.from(targetTable.getElementsByTagNameNS(ns, 'tr'));
    const headerIndex = rows.findIndex(row => getXmlText(row, ns).includes('Ijin/Sakit/Cuti'));
    if (headerIndex === -1) return;

    const dataRows = rows.slice(headerIndex + 1, headerIndex + 1 + kehadiran.length);
    dataRows.forEach((row, index) => {
      const item = kehadiran[index];
      const fill = getAttendanceColorMeta(item?.status_code || 'hadir').wordFill;
      applyWordRowFill(row, ns, fill);
    });

    zip.file('word/document.xml', new XMLSerializer().serializeToString(xmlDoc));
  } catch (error) {
    console.warn('Gagal mewarnai tabel kehadiran pada Word.', error);
  }
}

async function generateReport() {
  const m = parseInt(document.getElementById('bulan').value, 10);
  const y = parseInt(document.getElementById('tahun').value, 10);
  const n = parseInt(document.getElementById('reportNum').value, 10);
  curM = m;
  curY = y;

  await loadMonthData(y, m);
  await fetchHolidays(y);

  const label = `${MN[m - 1]} ${y}`;
  document.getElementById('kegBadge').textContent = label;
  document.getElementById('hadBadge').textContent = label;
  document.getElementById('catBadge').textContent = label;
  document.getElementById('emptyState').style.display = 'none';
  document.getElementById('reportSec').style.display = 'block';

  buildKeg(m, y);
  buildHad(m, y);
  fillNotesForm();
  localStorage.setItem('lkb_lastNum', n);
  switchTab('keg');
  toast('Laporan berhasil di-generate.', 'success');
}

function buildKeg(m, y) {
  const tb = document.getElementById('kegBody');
  tb.innerHTML = '';
  let no = 1;
  for (let d = 1; d <= daysInMonth(m, y); d++) {
    const date = new Date(y, m - 1, d);
    const ds = iso(date);
    if (isOff(date, ds)) continue;
    const rowData = kegData[ds] || {};
    const dayName = DN[date.getDay()];
    const tr = document.createElement('tr');
    tr.innerHTML = `
      <td style="text-align:center;color:#64748b;font-size:.78rem">${no++}.</td>
      <td>
        <div style="font-weight:600">${pad(d)} ${MN[m - 1]}</div>
        <div style="color:#64748b;font-size:.78rem">${y}</div>
        <div style="margin-top:2px;font-size:.76rem;background:#dcfce7;color:#166534;display:inline-block;padding:1px 7px;border-radius:10px">${dayName}</div>
      </td>
      <td><textarea rows="2" data-d="${ds}" data-f="keg" oninput="updateKeg(this)">${safe(rowData.keg)}</textarea></td>
      <td><textarea rows="3" data-d="${ds}" data-f="ura" oninput="updateKeg(this)">${safe(rowData.ura)}</textarea></td>
      <td><input data-d="${ds}" data-f="pem" oninput="updateKeg(this)" value="${safe(rowData.pem || DEFAULT_PEMBERI_TUGAS)}"></td>
      <td><input data-d="${ds}" data-f="pen" oninput="updateKeg(this)" value="${safe(rowData.pen || DEFAULT_PENYELENGGARA)}"></td>`;
    tb.appendChild(tr);
  }
}

function updateKeg(el) {
  const ds = el.dataset.d;
  const field = el.dataset.f;
  if (!kegData[ds]) kegData[ds] = {};
  kegData[ds][field] = el.value;
}

function buildHad(m, y) {
  const tb = document.getElementById('hadBody');
  tb.innerHTML = '';
  let no = 1;
  for (let d = 1; d <= daysInMonth(m, y); d++) {
    const date = new Date(y, m - 1, d);
    const ds = iso(date);
    const dayName = DN[date.getDay()];
    const off = isOff(date, ds);
    const rowData = attData[ds] || {};
    const tr = document.createElement('tr');

    if (off) {
      tr.classList.add('off');
      tr.innerHTML = `
        <td>${no++}.</td>
        <td>${dayName}</td>
        <td>${pad(d)} ${MN[m - 1]} ${y}</td>
        <td></td>
        <td></td>
        <td style="font-size:.78rem">${safe(isHol(ds) ? holidays[ds] : 'Akhir Pekan')}</td>`;
      tb.appendChild(tr);
      continue;
    }

    const normalized = normalizeAttendanceRow(rowData, date, ds);
    tr.innerHTML = `
      <td>${no++}.</td>
      <td>${dayName}</td>
      <td>${pad(d)} ${MN[m - 1]} ${y}</td>
      <td><input type="text" class="att-time" data-d="${ds}" data-f="masuk" oninput="updateAtt(this)" value="${safe(normalized.masuk)}"></td>
      <td><input type="text" class="att-time" data-d="${ds}" data-f="pulang" oninput="updateAtt(this)" value="${safe(normalized.pulang)}"></td>
      <td>
        <select data-d="${ds}" data-f="status" onchange="updateAttStatus(this)">
          ${renderAttendanceStatusOptions(normalized.status)}
        </select>
      </td>`;
    tb.appendChild(tr);
    applyAttendanceRowUi(tr, normalized.status);
  }
}

function updateAtt(el) {
  const ds = el.dataset.d;
  const field = el.dataset.f;
  if (!attData[ds]) attData[ds] = {};
  attData[ds][field] = el.value;
  if (!attData[ds].status) attData[ds].status = 'Hadir';
}

function fillNotesForm() {
  document.getElementById('capaian1').value = notesData.capaian1 || DEF_NOTES.capaian1;
  document.getElementById('capaian2').value = notesData.capaian2 || DEF_NOTES.capaian2;
  document.getElementById('evaluasi1').value = notesData.evaluasi1 || DEF_NOTES.evaluasi1;
  document.getElementById('saran1').value = notesData.saran1 || DEF_NOTES.saran1;
  document.getElementById('penutup').value = notesData.penutup || DEF_NOTES.penutup;
}

function collectNotes() {
  notesData = {
    capaian1: v('capaian1') || DEF_NOTES.capaian1,
    capaian2: v('capaian2') || DEF_NOTES.capaian2,
    evaluasi1: v('evaluasi1') || DEF_NOTES.evaluasi1,
    saran1: v('saran1') || DEF_NOTES.saran1,
    penutup: v('penutup') || DEF_NOTES.penutup
  };
}

function switchTab(tab) {
  document.querySelectorAll('.tab-btn').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.tab === tab);
  });
  document.getElementById('tab-keg').style.display = tab === 'keg' ? 'block' : 'none';
  document.getElementById('tab-had').style.display = tab === 'had' ? 'block' : 'none';
  document.getElementById('tab-cat').style.display = tab === 'cat' ? 'block' : 'none';
}

function collectAll() {
  document.querySelectorAll('#kegBody [data-d]').forEach(el => {
    const ds = el.dataset.d;
    const field = el.dataset.f;
    if (!kegData[ds]) kegData[ds] = {};
    kegData[ds][field] = el.value;
  });
  document.querySelectorAll('#hadBody [data-d]').forEach(el => {
    const ds = el.dataset.d;
    const field = el.dataset.f;
    if (!attData[ds]) attData[ds] = {};
    attData[ds][field] = el.value;
    if (field === 'status') attData[ds].ket = el.value === 'Hadir' ? '' : el.value;
  });
  collectNotes();
}

async function saveData() {
  if (!curM || !curY) {
    toast('Generate laporan dulu.', 'error');
    return;
  }
  collectAll();
  const reportNum = document.getElementById('reportNum').value;
  
  const payload = {
    bulan: curM,
    tahun: curY,
    reportNum: reportNum,
    kegData,
    attData,
    notesData
  };
  
  try {
    const res = await fetch('api.php?action=save', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    const result = await res.json();
    if (result.status === 'success') {
      localStorage.setItem('lkb_lastNum', reportNum);
      toast('Data tersimpan di database.', 'success');
    } else {
      toast('Gagal menyimpan: ' + result.message, 'error');
    }
  } catch (e) {
    toast('Error koneksi ke database.', 'error');
  }
}

async function loadMonthData(y, m) {
  try {
    const res = await fetch(`api.php?action=load&y=${y}&m=${m}`);
    const result = await res.json();
    
    if (result.status === 'success' && result.data) {
      const saved = result.data;
      kegData = saved.kegData || {};
      attData = saved.attData || {};
      notesData = { ...DEF_NOTES, ...(saved.notesData || {}) };
      if (saved.reportNum) document.getElementById('reportNum').value = saved.reportNum;
    } else {
      kegData = {};
      attData = {};
      notesData = { ...DEF_NOTES };
    }
  } catch (e) {
    console.error('Failed to load from DB', e);
    kegData = {};
    attData = {};
    notesData = { ...DEF_NOTES };
  }
}

function openHistory() {
  document.getElementById('histModal').classList.add('show');
  renderHistory();
}

function closeHistory() {
  document.getElementById('histModal').classList.remove('show');
}

async function renderHistory() {
  const list = document.getElementById('histList');
  list.innerHTML = '<p style="text-align: center; color: #64748b;">Memuat riwayat...</p>';
  
  try {
    const res = await fetch('api.php?action=list');
    const result = await res.json();
    
    if (result.status === 'success' && result.data.length > 0) {
      let html = '<table class="table" style="width: 100%;"><thead><tr><th>Periode</th><th>Laporan Ke</th><th>Terakhir Disimpan</th><th>Aksi</th></tr></thead><tbody>';
      result.data.forEach(item => {
        const dateStr = new Date(item.updated_at).toLocaleString('id-ID');
        html += `
          <tr>
            <td>${MN[item.bulan - 1]} ${item.tahun}</td>
            <td>${item.reportNum}</td>
            <td>${dateStr}</td>
            <td>
              <button class="btn btn-primary" style="padding: 4px 8px; font-size: 0.8rem;" onclick="loadReportFromHistory(${item.tahun}, ${item.bulan})">Buka</button>
              <button class="btn btn-outline" style="padding: 4px 8px; font-size: 0.8rem; color: #ef4444; border-color: #ef4444;" onclick="deleteReport(${item.tahun}, ${item.bulan})">Hapus</button>
            </td>
          </tr>
        `;
      });
      html += '</tbody></table>';
      list.innerHTML = html;
    } else {
      list.innerHTML = '<p style="text-align: center; color: #64748b;">Belum ada riwayat laporan.</p>';
    }
  } catch (e) {
    list.innerHTML = '<p style="text-align: center; color: #ef4444;">Gagal memuat riwayat.</p>';
  }
}

async function deleteReport(y, m) {
  if (!confirm(`Hapus laporan bulan ${MN[m - 1]} ${y}?`)) return;
  try {
    const res = await fetch(`api.php?action=delete&y=${y}&m=${m}`);
    const result = await res.json();
    if (result.status === 'success') {
      toast('Laporan dihapus.', 'success');
      renderHistory();
      if (curY === y && curM === m) {
         kegData = {}; attData = {}; notesData = { ...DEF_NOTES };
         buildKeg(m, y); buildHad(m, y); fillNotesForm();
      }
    }
  } catch (e) {
    toast('Gagal menghapus.', 'error');
  }
}

function loadReportFromHistory(y, m) {
  document.getElementById('tahun').value = y;
  document.getElementById('bulan').value = m;
  closeHistory();
  generateReport();
}

function buildTemplateData() {
  collectAll();
  const m = curM;
  const y = curY;
  const monthName = MN[m - 1];
  const reportNum = parseInt(document.getElementById('reportNum').value, 10);

  const kegiatan = [];
  let kegNo = 1;
  for (let d = 1; d <= daysInMonth(m, y); d++) {
    const date = new Date(y, m - 1, d);
    const ds = iso(date);
    if (isOff(date, ds)) continue;
    const item = kegData[ds] || {};
    kegiatan.push({
      no: kegNo++,
      tanggal: `${pad(d)} ${monthName} ${y}`,
      kegiatan: item.keg || '',
      uraian: item.ura || '',
      pemberi_tugas: item.pem || DEFAULT_PEMBERI_TUGAS,
      penyelenggara: item.pen || DEFAULT_PENYELENGGARA
    });
  }

  const kehadiran = [];
  let hadNo = 1;
  for (let d = 1; d <= daysInMonth(m, y); d++) {
    const date = new Date(y, m - 1, d);
    const ds = iso(date);
    const rowData = attData[ds] || {};
    const off = isOff(date, ds);
    const normalized = normalizeAttendanceRow(rowData, date, ds);
    const statusCode = getAttendanceStatusCode(normalized.status, off);
    kehadiran.push({
      no: hadNo++,
      hari: DN[date.getDay()],
      tanggal: `${pad(d)} ${monthName} ${y}`,
      masuk: off ? '' : normalized.masuk,
      pulang: off ? '' : normalized.pulang,
      ket: off ? (isHol(ds) ? holidays[ds] : 'Akhir Pekan') : (normalized.status === 'Hadir' ? '' : normalized.status),
      status: normalized.status,
      status_code: statusCode
    });
  }

  return {
    judul_laporan: cfg.judulLaporan,
    bulan_upper: monthName.toUpperCase(),
    bulan: monthName,
    tahun: y,
    nama: cfg.nama,
    jabatan_laporan: cfg.judulLaporan,
    jabatan_ttd: cfg.jabatan,
    jabatan_atasan: cfg.jabAtasan,
    atasan: cfg.atasan,
    nip: cfg.nip,
    instansi: cfg.instansi,
    kontrak_mulai: cfg.kAwal,
    kontrak_akhir: cfg.kAkhir,
    bulan_ke_sebut: ordinalId(reportNum),
    capaian_1: notesData.capaian1,
    capaian_2: notesData.capaian2,
    evaluasi_1: notesData.evaluasi1,
    saran_1: notesData.saran1,
    penutup: notesData.penutup,
    kegiatan,
    kehadiran
  };
}

async function doDownloadWord() {
  if (!curM || !curY) {
    toast('Generate laporan dulu.', 'error');
    return;
  }

  const libsReady = await ensureDocxLibraries();
  if (!libsReady) {
    toast('Library DOCX gagal dimuat. Cek internet atau pakai versi dengan library lokal.', 'error');
    return;
  }

  try {
    toast('Menyiapkan file Word sesuai template...', 'info');
    const data = buildTemplateData();
    const content = await getTemplateArrayBuffer();
    const zip = new window.PizZip(content);
    const DocxtemplaterCtor = getDocxtemplaterCtor();
    const doc = new DocxtemplaterCtor(zip, {
      paragraphLoop: true,
      linebreaks: true
    });

    doc.render(data);
    colorAttendanceTableInWord(doc.getZip(), data.kehadiran);

    const blob = doc.getZip().generate({
      type: 'blob',
      mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
    });

    const monthName = MN[curM - 1];
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Laporan_Bulanan_${monthName}_${curY}.docx`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    toast('File Word berhasil diunduh.', 'success');
  } catch (err) {
    console.error(err);
    toast(`Gagal membuat Word: ${err.message}`, 'error');
  }
}

