const daysInMonth = (m, y) => new Date(y, m, 0).getDate();
const pad = n => String(n).padStart(2, '0');
const iso = d => `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
const safe = value => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;');
const esc = value => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

function ordinalId(n) {
  const map = {
    1:'Pertama',2:'Kedua',3:'Ketiga',4:'Keempat',5:'Kelima',6:'Keenam',7:'Ketujuh',8:'Kedelapan',9:'Kesembilan',10:'Kesepuluh',
    11:'Kesebelas',12:'Kedua Belas',13:'Ketiga Belas',14:'Keempat Belas',15:'Kelima Belas',16:'Keenam Belas',17:'Ketujuh Belas',18:'Kedelapan Belas',19:'Kesembilan Belas',20:'Kedua Puluh'
  };
  return map[n] || `${n}`;
}

function toast(message, type = 'info') {
  const wrap = document.getElementById('toastWrap');
  const el = document.createElement('div');
  el.className = `toast toast-${type}`;
  el.textContent = message;
  wrap.appendChild(el);
  setTimeout(() => el.remove(), 3500);
}
